302	test('drain-queue golden: real-config endpoint shape, click Drain, worker row, no gemini cross-pollination, no 19-failure pattern', async ({
303		page
304	}) => {
305		const state: { workers: WorkerNode[]; dispatched: { count: number } } = {
306			workers: [],
307			dispatched: { count: 0 }
308		};
309		await installGraphqlMocks(page, state);
310	
311		// 1. Navigate to project home and click "Drain queue".
312		await page.goto(HOME_URL);
313		await expect(page.getByRole('heading', { name: PROJECT.name })).toBeVisible();
314		await expect(page.getByText(/4 ready beads/)).toBeVisible();
315	
316		const drainCta = page.getByRole('button', { name: 'Drain queue' });
317		await expect(drainCta).toBeEnabled();
318		await drainCta.click();
319	
320		// 2. Confirm dialog dispatches the execute-loop worker.
321		const startBtn = page.getByRole('button', { name: 'Start Drain queue' });
322		await expect(startBtn).toBeVisible();
323		const dispatchStartedAt = Date.now();
324		await startBtn.click();
325	
326		// 3. Within 5s a worker row materializes (via the success card linking to it).
327		const workerLink = page.getByRole('link', { name: /worker-drain-1/ });
328		await expect(workerLink).toBeVisible({ timeout: 5000 });
329		const elapsedMs = Date.now() - dispatchStartedAt;
330		expect(elapsedMs).toBeLessThan(5000);
331		expect(state.dispatched.count).toBe(1);
332	
333		// 4. The dispatched worker's harness is backed by a live endpoint and has
334		// no gemini cross-pollination.
335		const dispatched = state.workers[0];
336		expect(harnessBoundToLiveEndpoint(dispatched)).toBe(true);
337		expect(noGeminiCrossContamination(dispatched)).toBe(true);
338	
339		// 5. Drive the worker through "ran 4 attempts, all succeeded" then assert
340		// the workers list reflects success and never the 19-failure pattern.
341		state.workers = [
342			makeWorker({
343				state: 'done',
344				status: 'success',
345				attempts: QUEUE_READY,
346				successes: QUEUE_READY,
347				failures: 0,
348				finishedAt: '2026-04-29T12:05:00Z',
349				currentBead: null,
350				lastError: null
351			})
352		];
353	
354		await page.goto(WORKERS_URL);
355		await expect(page.getByRole('heading', { name: 'Workers' })).toBeVisible();
356		await expect(page.getByText('worker-d')).toBeVisible();
357		await expect(page.getByText('done')).toBeVisible();
358	
359		const finalWorker = state.workers[0];
360		// Status is success OR a typed error string with a recorded reason.
361		const successOrTypedError =
362			finalWorker.status === 'success' ||
363			(typeof finalWorker.status === 'string' &&
364				finalWorker.status.length > 0 &&
365				typeof finalWorker.lastError === 'string' &&
366				finalWorker.lastError.length > 0);
367		expect(successOrTypedError).toBe(true);
368	
369		// Attempts count matches the work done (successes + failures).
370		expect(attemptsMatchWorkDone(finalWorker)).toBe(true);
371	
372		// Critical regression guards: never the 19-failure pattern, never gemini
373		// cross-pollination, harness still bound to a live endpoint at completion.
374		expect(finalWorker.failures).not.toBe(19);
375		expect(finalWorker.attempts).toBeLessThanOrEqual(QUEUE_READY);
376		expect(noGeminiCrossContamination(finalWorker)).toBe(true);
377		expect(harnessBoundToLiveEndpoint(finalWorker)).toBe(true);
378	});
